// Get data directly from the Webhook node
const body = $('Webhook').item.json.body;

const meetingTitle = body.meeting_title;
const recordingDate = body.created_at;
const summary = body.default_summary.markdown_formatted;
const transcript = body.transcript;
const attendees = body.calendar_invitees;
const recordingUrl = body.url;
const shareUrl = body.share_url;
const actionItems = body.action_items;

// Clean up the summary by removing URLs in markdown links
let cleanedSummary = summary
  .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
  .replace(/\n{3,}/g, '\n\n');

// Format the transcript (group consecutive messages from same speaker)
let formattedTranscript = '';
let currentSpeaker = null;
let currentText = [];

transcript.forEach((entry, index) => {
  const speakerName = entry.speaker.display_name;
  const text = entry.text;

  if (speakerName === currentSpeaker) {
    currentText.push(text);
  } else {
    if (currentSpeaker !== null) {
      formattedTranscript += `**${currentSpeaker}:**\n${currentText.join(' ')}\n\n`;
    }
    currentSpeaker = speakerName;
    currentText = [text];
  }

  if (index === transcript.length - 1) {
    formattedTranscript += `**${currentSpeaker}:**\n${currentText.join(' ')}`;
  }
});

// Format attendees as simple array
const attendeesList = attendees.map(attendee => ({
  name: attendee.name,
  email: attendee.email
}));

// Return everything as separate fields
return {
  json: {
    meeting_title: meetingTitle,
    date: recordingDate,
    attendees: attendeesList,
    recording_url: recordingUrl,
    playback_url: shareUrl,
    summary: cleanedSummary.trim(),
    transcript: formattedTranscript.trim(),
    action_items: actionItems
  }
};

